solution_code:
#include <iostream>
#include <string>

class Person {
public:
    std::string name;
    int age = 0;
    void printInfo() {
        std::cout << "Name: " << name << ", Age: " << age << "\n";
    }
};

class Employee : public Person {
public:
    int id = 0;
    std::string dept;
    void printEmployee() {
        printInfo();
        std::cout << "Employee ID: " << id << ", Dept: " << dept << "\n";
    }
};

int main() {
    Employee e;
    std::cin >> e.name >> e.age >> e.id >> e.dept;
    e.printEmployee();
    return 0;
}

