solution_code:
#include <iostream>

int countFields(int baseFields, int derivedFields) {
    return baseFields + derivedFields;
}

int main() {
    int b, d;
    std::cin >> b >> d;
    int total = countFields(b, d);
    std::cout << "Total fields: " << total << "\n";
    return 0;
}
